const item = $input.item.json;

const scenes = Array.isArray(item.scenes) ? item.scenes : [];
const fullText = [
  item.video_title,
  item.hook,
  item.voiceover_full,
  ...scenes.map(s => s.voiceover || s.voiceOver || s.voice_over || s.voice || s.text_on_screen || s.textOnScreen || '')
].filter(Boolean).join(' ');

const bannedPhrases = [
  'ดีที่สุด',
  'อันดับ 1',
  'อันดับหนึ่ง',
  'การันตีผลลัพธ์ 100%',
  'การันตี 100%',
  'รักษาหาย',
  'หายขาด'
];

const foundIssues = [];

for (const phrase of bannedPhrases) {
  if (fullText.includes(phrase)) {
    foundIssues.push('พบคำเคลมเกินจริง: ' + phrase);
  }
}

const scriptStatus = foundIssues.length > 0 ? 'needs_review' : 'safe';

return {
  json: {
    ...item,
    safety_notes: foundIssues,
    script_status: scriptStatus,
    approval_status: 'pending_approval',
    posting_allowed: false
  }
};

const items = $input.all();

return items.map(({ json }) => {
  const item = json;

  const scenes =
    Array.isArray(item.scenes) ? item.scenes :
    Array.isArray(item.script) ? item.script :
    Array.isArray(item.video_scenes) ? item.video_scenes :
    [];

  const voiceoverFull =
    item.voiceover_full ||
    item.voiceOverFull ||
    item.voiceoverFull ||
    item.voiceover ||
    item.voiceOver ||
    item.voice_over ||
    item.narration ||
    item.narration_text ||
    scenes
      .map(s =>
        s.voiceover ||
        s.voiceOver ||
        s.voice_over ||
        s.voice ||
        s.text_on_screen ||
        s.textOnScreen ||
        ''
      )
      .filter(Boolean)
      .join(' ');

  if (!voiceoverFull || !voiceoverFull.trim()) {
    throw new Error(
      'Missing voiceover text. Current root keys: ' +
      Object.keys(item).join(', ') +
      ' | scene keys: ' +
      (scenes[0] ? Object.keys(scenes[0]).join(', ') : 'no scenes')
    );
  }

  const normalizedScenes = scenes.map((s, index) => ({
    scene_number: s.scene_number || s.scene || index + 1,
    duration_sec: Number(s.duration_sec || s.duration || 4),
    text_on_screen: s.text_on_screen || s.textOnScreen || '',
    voiceover: s.voiceover || s.voiceOver || s.voice_over || s.voice || '',
    visual_instruction: s.visual_instruction || s.visualInstruction || '',
    transition: s.transition || 'cut'
  }));

  return {
    json: {
      ...item,
      scenes: normalizedScenes,
      voiceover_full: voiceoverFull.trim(),
      voiceover_char_count: voiceoverFull.trim().length,
      voiceover_status: 'normalized'
    }
  };
});

const item = $json;
const scenes = Array.isArray(item.scenes) ? item.scenes : [];

if (!scenes.length) {
  throw new Error('Missing scenes for subtitle generation');
}

let currentTime = 0;

const subtitles = scenes.map((scene, index) => {
  const duration = Number(scene.duration_sec || scene.duration || 4);

  const text =
    scene.voiceover ||
    scene.voiceOver ||
    scene.voice_over ||
    scene.voice ||
    scene.text_on_screen ||
    scene.textOnScreen ||
    '';

  if (!text.trim()) {
    throw new Error(`Missing subtitle text at scene ${index + 1}`);
  }

  const subtitle = {
    index: index + 1,
    start: Number(currentTime.toFixed(2)),
    end: Number((currentTime + duration).toFixed(2)),
    text: text.trim(),
  };

  currentTime += duration;
  return subtitle;
});

return {
  json: {
    ...item,
    subtitles,
    subtitle_status: 'generated',
    total_duration_sec: Number(currentTime.toFixed(2)),
  },
};

const item = $json;

const imageUrls = Array.isArray(item.image_urls)
  ? item.image_urls.filter(Boolean)
  : [
      item.image_url,
      item.public_image_url,
      item.product_image_url,
    ].filter(Boolean);

const audioUrl =
  item.audio_url ||
  item.public_audio_url ||
  item.audioUrl ||
  item.publicAudioUrl ||
  item.result?.audio_url ||
  item.result?.url ||
  item.data?.audio_url ||
  item.data?.url ||
  "";

const scenes = Array.isArray(item.scenes) && item.scenes.length
  ? item.scenes
  : [
      {
        scene_number: 1,
        duration_sec: Number(item.duration_seconds || 4),
        text: item.voiceover_full || item.text_preview || "วิดีโอสินค้า",
        voiceover: item.voiceover_full || item.text_preview || "วิดีโอสินค้า",
      },
    ];

const subtitles = Array.isArray(item.subtitles) && item.subtitles.length
  ? item.subtitles
  : scenes.map((scene, index) => {
      const start = scenes
        .slice(0, index)
        .reduce((sum, s) => sum + Number(s.duration_sec || 4), 0);
      const end = start + Number(scene.duration_sec || 4);

      return {
        index: index + 1,
        start,
        end,
        text: scene.voiceover || scene.text || "วิดีโอสินค้า",
      };
    });

if (!imageUrls.length) {
  throw new Error("Build Render Payload missing image_urls/public_image_url");
}

if (!audioUrl) {
  throw new Error("Build Render Payload missing audio_url/public_audio_url");
}
function cleanThaiOverlay(value, fallback = '') {
  return String(value || fallback)
    .normalize('NFC')
    .replace(/[\u200B-\u200D\uFEFF]/g, '')
    .replace(/[^\u0E00-\u0E7F0-9\s.,!?()\-:]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

const overlayTitle =
  item.brand_context === 'syncflow'
    ? 'แชทไม่หาย งานไม่หลุด'
    : 'แอร์ผิดปกติ อย่าปล่อยไว้';

const safeTitle = cleanThaiOverlay(
  overlayTitle,
  'แอร์ผิดปกติ อย่าปล่อยไว้'
);

return {
  json: {
    ...item,

    render_status: "payload_ready",

    product_id: item.product_id || item.job_id || `line-video-${Date.now()}`,

    // เปลี่ยน default ไม่ให้กลับไปเป็น "สินค้าไทย PAA"
    product_name: safeTitle,

    // ใช้ title ไทยล้วน ป้องกัน □□□
    title: safeTitle,
    video_title: safeTitle,

    output_format: "mp4",

    width: 1080,
    height: 1920,
    fps: 30,

    brand: {
      ...(item.brand || {}),
      // Force renderer title source to Thai-only text; never use English brand/business names.
      name: safeTitle,
      background_color: item.brand?.background_color || item.brand?.background || item.brand_color || "#0f172a",
      text_color: item.brand?.text_color || item.brand?.foreground || "#ffffff",
      primary_color: item.brand?.primary_color || item.brand?.accent || "#22c55e",
    },

    scenes,
    subtitles,

    image_urls: imageUrls,
    image_url: imageUrls[0],
    audio_url: audioUrl,

    overlay_mode: "none",
    center_overlay_enabled: false,
    show_center_overlay: false,
    accent_line_enabled: false,
    progress_line_enabled: false,
    show_bottom_line: false,

    real_posting_enabled: false,
    posting_allowed: false,
  },
};

const json = $json;

if (json.render_status !== 'payload_ready') {
  throw new Error('Render payload is not ready');
}

if (!Array.isArray(json.scenes) || json.scenes.length === 0) {
  throw new Error('Missing scenes');
}

if (!Array.isArray(json.subtitles) || json.subtitles.length === 0) {
  throw new Error('Missing subtitles');
}

if (!json.audio_url) {
  throw new Error('Missing audio_url');
}

if (!json.width || !json.height || !json.fps) {
  throw new Error('Missing video render dimensions/fps');
}

return {
  json: {
    ...json,
    validation_status: 'ok',
    validated_at: new Date().toISOString(),
  }
};

const json = $json;
const id = json.product_id || 'TEST-VIDEO-001';

return {
  json: {
    ...json,
    ok: true,
    render_mode: 'mock',
    video_url: `https://example.com/rendered/${id}.mp4`,
    thumbnail_url: `https://example.com/rendered/${id}.jpg`,
    duration_sec: json.duration_target_sec || 30,
    file_size_mb: 8.5,
    render_status: 'completed'
  }
};

const baseApprovalUrl = 'https://admin.paaair.online/webhook/video-approval';
const publicMediaBase = 'https://admin.paaair.online/media/';

function cleanString(value) {
  return String(value || '').trim();
}

function toPublicMediaUrl(value) {
  const raw = cleanString(value);
  if (!raw) return '';

  if (raw.startsWith('https://admin.paaair.online/media/')) {
    return raw;
  }

  const marker = '/media/';
  const index = raw.indexOf(marker);

  if (index >= 0) {
    const filename = raw.slice(index + marker.length);
    return publicMediaBase + encodeURIComponent(filename).replace(/%2F/g, '/');
  }

  return raw;
}

const jobId = cleanString(
  $json.job_id ||
  $json.product_id ||
  $json.messageId ||
  $json.message_id
);

const productId = cleanString($json.product_id || jobId);

const token = cleanString(
  $json.approval_token ||
  $json.token ||
  $json.messageId ||
  jobId
);

if (!jobId) {
  throw new Error('Missing job_id/product_id/messageId for approval URL');
}

if (!token) {
  throw new Error('Missing approval token for approval URL');
}

const videoUrl = toPublicMediaUrl(
  $json.public_video_url ||
  $json.video_url ||
  $json.output_url ||
  $json.render_url ||
  $json.media_url
);

const thumbnailUrl = toPublicMediaUrl(
  $json.public_thumbnail_url ||
  $json.thumbnail_url ||
  $json.image_url ||
  ''
);

return {
  json: {
    ...$json,

    job_id: jobId,
    product_id: productId,
    approval_token: token,

    video_url: videoUrl,
    public_video_url: videoUrl,
    thumbnail_url: thumbnailUrl,
    public_thumbnail_url: thumbnailUrl,

    approve_url:
      baseApprovalUrl +
      '?action=approve' +
      '&job_id=' +
      encodeURIComponent(jobId) +
      '&product_id=' +
      encodeURIComponent(productId) +
      '&token=' +
      encodeURIComponent(token),

    reject_url:
      baseApprovalUrl +
      '?action=reject' +
      '&job_id=' +
      encodeURIComponent(jobId) +
      '&product_id=' +
      encodeURIComponent(productId) +
      '&token=' +
      encodeURIComponent(token),

    real_posting_enabled: false,
    posting_allowed: false,
  },
};

const q = $json.query || $json;

const action = String(q.action || '').trim().toLowerCase();
const token = String(q.token || '').trim();
const jobId = String(q.job_id || q.product_id || '').trim();
const productId = String(q.product_id || q.job_id || '').trim();

const validAction = action === 'approve' || action === 'reject';
const tokenMatchesGeneratedLink = Boolean(
  token && jobId && (
    token === jobId ||
    token === productId ||
    jobId === `line-image-${token}` ||
    productId === `line-image-${token}` ||
    jobId.endsWith(token) ||
    productId.endsWith(token)
  )
);

if (!validAction || !token || !jobId || !tokenMatchesGeneratedLink) {
  return {
    json: {
      ok: false,
      valid: false,
      reason: 'invalid_approval_request',
      action,
      job_id: jobId,
      product_id: productId,
      real_posting_enabled: false,
      posting_allowed: false,
      owner_response: 'ลิงก์อนุมัติไม่ถูกต้องหรือหมดอายุ',
    },
  };
}

return {
  json: {
    ...$json,
    ok: true,
    valid: true,
    action,
    job_id: jobId,
    product_id: productId,
    approval_status: 'validated',
    real_posting_enabled: false,
    posting_allowed: false,
  },
};

