parameters.jsCode:
const items = $input.all();

function cleanString(value, fallback = '') {
  const s = String(value ?? '').trim();
  return s || fallback;
}

function cleanText(value, fallback = '') {
  return cleanString(value, fallback)
    .normalize('NFC')
    .replace(/[\u200B-\u200D\uFEFF]/g, '')
    .replace(/[^\u0E00-\u0E7Fa-zA-Z0-9\s.,!?()\-:]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function extractJson(value) {
  if (typeof value === 'object' && value !== null) return value;

  const raw = String(value ?? '').trim();

  if (!raw) return {};

  try {
    return JSON.parse(raw);
  } catch (_) {}

  const match = raw.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      return JSON.parse(match[0]);
    } catch (_) {}
  }

  return {};
}

return items.map(({ json }) => {
  const candidate =
    json.ai_script_json ||
    json.output ||
    json.text ||
    json.response ||
    json.result ||
    json.message ||
    json.data ||
    json;

  const parsed = extractJson(candidate);

  const hook = cleanText(parsed.hook || json.hook, '');
  const voiceoverFull = cleanText(
    parsed.voiceover_full ||
    json.voiceover_full ||
    parsed.voiceover ||
    json.voiceover ||
    '',
    ''
  );

  const scenesRaw = Array.isArray(parsed.scenes)
    ? parsed.scenes
    : Array.isArray(json.scenes)
      ? json.scenes
      : [];

