    json.image_id ||
    json.imageId
  );

  if (existing && !existing.includes('cdn.example.com') && !existing.includes('/bucket/uploads')) {
    return existing;
  }

  if (!messageId) return existing;

  const base = cleanString(
    $env.PUBLIC_LINE_IMAGE_BASE_URL ||
    $env.PUBLIC_MINIO_UPLOAD_BASE_URL ||
