    .replace(/[\u200B-\u200D\uFEFF]/g, '')
    .replace(/[^\u0E00-\u0E7F0-9\s.,!?()\-:]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

const overlayTitle =
  item.brand_context === 'syncflow'
    ? 'แชทไม่หาย งานไม่หลุด'
    : 'แอร์ผิดปกติ อย่าปล่อยไว้';

const safeTitle = cleanThaiOverlay(
  overlayTitle,
  'แอร์ผิดปกติ อย่าปล่อยไว้'
);

return {
  json: {
    ...item,

    render_status: "payload_ready",
    payload_ready_at: new Date().toISOString(),

    product_id: item.product_id || item.job_id || `line-video-${Date.now()}`,
    studio_asset_id: studioAssetId || null,
    uploaded_asset_id: item.uploaded_asset_id || item.asset_id || null,

    // เปลี่ยน default ไม่ให้กลับไปเป็น "สินค้าไทย PAA"
    product_name: safeTitle,

    // ใช้ title ไทยล้วน ป้องกัน □□□
    title: safeTitle,
    video_title: safeTitle,

    output_format: "mp4",

    width: 1080,
    height: 1920,
    fps: 30,

    brand: {
      ...(item.brand || {}),
      // Force renderer title source to Thai-only text; never use English brand/business names.
      name: safeTitle,
      background_color: item.brand?.background_color || item.brand?.background || item.brand_color || "#0f172a",
      text_color: item.brand?.text_color || item.brand?.foreground || "#ffffff",
      primary_color: item.brand?.primary_color || item.brand?.accent || "#22c55e",
    },

    scenes,
    subtitles,

    image_urls: imageUrls,
    image_url: primaryImageUrl,
    public_image_url: primaryImageUrl,
    source_image_url: primaryImageUrl,
    product_image_url: primaryImageUrl,
    input_image_url: primaryImageUrl,
    main_image_url: primaryImageUrl,
    uploaded_image_url: primaryImageUrl,
    primary_image_url: primaryImageUrl,
    cover_image_url: primaryImageUrl,
    visual_url: primaryImageUrl,

    images: imageUrls.map((url, index) => ({
      url,
      image_url: url,
      public_image_url: url,
      source_image_url: url,
      role: index === 0 ? "primary" : "secondary",
    })),

    media: {
      ...(item.media || {}),
      image_url: primaryImageUrl,
      public_image_url: primaryImageUrl,
      image_urls: imageUrls,
      audio_url: audioUrl,
    },

    input: {
      ...(item.input || {}),
      image_url: primaryImageUrl,
      public_image_url: primaryImageUrl,
      image_urls: imageUrls,
      audio_url: audioUrl,
    },

    assets: {
      ...(item.assets || {}),
      image_url: primaryImageUrl,
      public_image_url: primaryImageUrl,
      image_urls: imageUrls,
      audio_url: audioUrl,
    },

    audio_url: audioUrl,

    overlay_mode: "none",
    center_overlay_enabled: false,
    show_center_overlay: false,
    accent_line_enabled: false,
    progress_line_enabled: false,
    show_bottom_line: false,

    preview_only: true,
    real_posting_enabled: false,
    posting_allowed: false,
    line_broadcast_enabled: false,
    schedule_enabled: false,
  },
};

const json = $json;

if (json.render_status !== 'payload_ready') {
  throw new Error('Render payload is not ready');
}

if (!Array.isArray(json.scenes) || json.scenes.length === 0) {
  throw new Error('Missing scenes');
}

if (!Array.isArray(json.subtitles) || json.subtitles.length === 0) {
  throw new Error('Missing subtitles');
}

if (!json.audio_url) {
  throw new Error('Missing audio_url');
}

if (!json.width || !json.height || !json.fps) {
  throw new Error('Missing video render dimensions/fps');
}

return {
  json: {
    ...json,
    validation_status: 'ok',
    validated_at: new Date().toISOString(),
  }
};

const json = $json;
const id = json.product_id || 'TEST-VIDEO-001';

return {
  json: {
    ...json,
    ok: true,
    render_mode: 'mock',
    video_url: `https://example.com/rendered/${id}.mp4`,
    thumbnail_url: `https://example.com/rendered/${id}.jpg`,
    duration_sec: json.duration_target_sec || 30,
    file_size_mb: 8.5,
    render_status: 'completed'
  }
};

const baseApprovalUrl = 'https://admin.paaair.online/webhook/video-approval';
const publicMediaBase = 'https://admin.paaair.online/media/';

function cleanString(value) {
  return String(value || '').trim();
}

function toPublicMediaUrl(value) {
  const raw = cleanString(value);
  if (!raw) return '';

  if (raw.startsWith('https://admin.paaair.online/media/')) {
    return raw;
  }

  const marker = '/media/';
  const index = raw.indexOf(marker);

  if (index >= 0) {
    const filename = raw.slice(index + marker.length);
    return publicMediaBase + encodeURIComponent(filename).replace(/%2F/g, '/');
  }

  return raw;
}

const jobId = cleanString(
  $json.job_id ||
  $json.product_id ||
  $json.messageId ||
  $json.message_id
);

const productId = cleanString($json.product_id || jobId);

const token = cleanString(
  $json.approval_token ||
  $json.token ||
  $json.messageId ||
  jobId
);

if (!jobId) {
  throw new Error('Missing job_id/product_id/messageId for approval URL');
}

if (!token) {
  throw new Error('Missing approval token for approval URL');
}

const videoUrl = toPublicMediaUrl(
  $json.public_video_url ||
  $json.video_url ||
  $json.output_url ||
  $json.render_url ||
  $json.media_url
);

const thumbnailUrl = toPublicMediaUrl(
  $json.public_thumbnail_url ||
  $json.thumbnail_url ||
  $json.image_url ||
  ''
);

return {
  json: {
    ...$json,

    job_id: jobId,
    product_id: productId,
    approval_token: token,

    video_url: videoUrl,
    public_video_url: videoUrl,
    thumbnail_url: thumbnailUrl,
    public_thumbnail_url: thumbnailUrl,

    approve_url:
      baseApprovalUrl +
      '?action=approve' +
      '&job_id=' +
      encodeURIComponent(jobId) +
      '&product_id=' +
      encodeURIComponent(productId) +
      '&token=' +
      encodeURIComponent(token),

    reject_url:
      baseApprovalUrl +
      '?action=reject' +
      '&job_id=' +
      encodeURIComponent(jobId) +
      '&product_id=' +
      encodeURIComponent(productId) +
      '&token=' +
      encodeURIComponent(token),

    real_posting_enabled: false,
    posting_allowed: false,
  },
};

