parameters.jsCode:
const items = $input.all();

function cleanString(value, fallback = '') {
  const s = String(value ?? '').trim();
  return s || fallback;
}

function cleanText(value, fallback = '') {
  return cleanString(value, fallback)
    .normalize('NFC')
    .replace(/[\u200B-\u200D\uFEFF]/g, '')
    .replace(/[^\u0E00-\u0E7Fa-zA-Z0-9\s.,!?()\-:]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function extractJson(value) {
  if (typeof value === 'object' && value !== null) return value;

  const raw = String(value ?? '').trim();

  if (!raw) return {};

  try {
    return JSON.parse(raw);
  } catch (_) {}

  const match = raw.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      return JSON.parse(match[0]);
    } catch (_) {}
  }

  return {};
}

return items.map(({ json }) => {
  const candidate =
    json.ai_script_json ||
    json.output ||
    json.text ||
    json.response ||
    json.result ||
    json.message ||
    json.data ||
    json;

  const parsed = extractJson(candidate);

  const hook = cleanText(parsed.hook || json.hook, '');
  const voiceoverFull = cleanText(
    parsed.voiceover_full ||
    json.voiceover_full ||
    parsed.voiceover ||
    json.voiceover ||
    '',
    ''
  );

  const scenesRaw = Array.isArray(parsed.scenes)
    ? parsed.scenes
    : Array.isArray(json.scenes)
      ? json.scenes
      : [];

  const scenes = scenesRaw.slice(0, 5).map((scene, index) => {
    const text = cleanText(scene.text || scene.title || hook || 'ข้อความบนจอ', 'ข้อความบนจอ');
    const voiceover = cleanText(scene.voiceover || scene.text || voiceoverFull || text, text);

    return {
      scene_number: Number(scene.scene_number || index + 1),
      duration_sec: Number(scene.duration_sec || 4),
      text: text.slice(0, 60),
      voiceover,
      visual_instruction: cleanText(scene.visual_instruction || '', ''),
      transition: cleanText(scene.transition || 'fade', 'fade'),
    };
  });

  const finalScenes = scenes.length
    ? scenes
    : [
        {
          scene_number: 1,
          duration_sec: 4,
          text: cleanText(hook || 'เริ่มต้นคลิป', 'เริ่มต้นคลิป'),
          voiceover: cleanText(voiceoverFull || hook || 'เริ่มต้นคลิป', 'เริ่มต้นคลิป'),
          visual_instruction: '',
          transition: 'fade',
        },
      ];

  const finalVoiceover = voiceoverFull || finalScenes.map(s => s.voiceover).join(' ');

  if (!finalVoiceover) {
    throw new Error('Missing voiceover_full from AI script output');
  }

  return {
    json: {
      ...json,

      hook,
      voiceover_full: finalVoiceover,
      scenes: finalScenes,

      caption_reels: cleanText(parsed.caption_reels || json.caption_reels, ''),
      call_to_action: cleanText(
        parsed.call_to_action ||
        json.call_to_action ||
        (json.brand_context === 'syncflow'
          ? 'ทัก LINE เพื่อดูเดโม SyncFlow'
          : 'ทัก LINE เพื่อส่งรูปหรือสอบถามอาการ'),
        ''
      ),

      script_status: 'ready',
      script_normalized_at: new Date().toISOString(),

      real_posting_enabled: false,
      posting_allowed: false,
    },
  };
});

const items = $input.all();

function clean(value, fallback = '') {
  const s = String(value ?? '').trim();
  return s || fallback;
}

return items.map(({ json }) => {
  const raw = clean(json.brand_context || json.brandContext || $env.DEFAULT_VIDEO_BRAND_CONTEXT || 'paa_air').toLowerCase();
  const brand_context = raw.includes('sync') ? 'syncflow' : 'paa_air';
  return { json: { ...json, brand_context } };
});

const items = $input.all();

function cleanString(value, fallback = '') {
  const s = String(value ?? '').trim();
  return s || fallback;
}

function buildPublicImageUrl(json) {
  const existing = cleanString(
    json.public_image_url ||
    json.publicImageUrl ||
    json.image_url ||
    json.imageUrl
  );

  const messageId = cleanString(
    json.messageId ||
    json.message_id ||
    json.image_id ||
    json.imageId
  );

  if (existing && !existing.includes('cdn.example.com') && !existing.includes('/bucket/uploads')) {
    return existing;
  }

  if (!messageId) return existing;

  const base = cleanString(
    $env.PUBLIC_LINE_IMAGE_BASE_URL ||
    $env.PUBLIC_MINIO_UPLOAD_BASE_URL ||
    'https://s3.paaair.online/paa-video-assets/uploads'
  ).replace(/\/+$/, '');

  return `${base}/${messageId}.jpg`;
}

function detectBrandContext(json) {
  const raw = [
    json.brand_context,
    json.brand,
    json.brand_name,
    json.business_name,
    json.product_name,
    json.caption,
    json.message,
    json.text,
    json.raw_text,
    json.notes,
  ]
    .filter(Boolean)
    .join(' ')
    .toLowerCase();

  if (
    raw.includes('syncflow') ||
    raw.includes('paa tech') ||
    raw.includes('ระบบจัดการแชท') ||
    raw.includes('รับแชท') ||
    raw.includes('คิวหลุด') ||
    raw.includes('งานไม่หลุด')
  ) {
    return 'syncflow';
  }

  if (
    raw.includes('paa air') ||
    raw.includes('pa air') ||
    raw.includes('pa cooling') ||
    raw.includes('แอร์') ||
    raw.includes('ล้างแอร์') ||
    raw.includes('ซ่อมแอร์') ||
    raw.includes('ติดตั้งแอร์')
  ) {
    return 'paa_air';
  }

  return 'paa_air';
}

function getBrandProfile(brandContext) {
  if (brandContext === 'syncflow') {
    return {
      business_name: 'SyncFlow by PAA Tech',
      brand_name: 'SyncFlow by PAA Tech',
      brand_color: '#f97316',
      business_type: 'ระบบช่วยธุรกิจบริการรับแชท เก็บงาน จัดคิว และแจ้งเตือนทีมผ่าน LINE',
      service_area: 'ให้บริการธุรกิจบริการทั่วไทย',
      target_customer: 'เจ้าของธุรกิจบริการ แอดมินร้าน ทีมช่าง ร้านซ่อม สปา คลินิก และธุรกิจที่รับงานผ่านแชท',
      product_name: 'ระบบจัดการแชทและงานบริการ',
      title: 'เปลี่ยนทุกข้อความให้เป็นงาน',
      video_title: 'เปลี่ยนทุกข้อความให้เป็นงาน',
