}

return items.map(({ json }) => {
  const publicImageUrl = buildPublicImageUrl(json);
  const messageId = cleanString(
    json.messageId || json.message_id || json.image_id || json.imageId,
    String(Date.now())
  );

  if (!publicImageUrl) throw new Error('Missing public_image_url after LINE image upload');

  const brandContext = detectBrandContext(json);
  const profile = getBrandProfile(brandContext);

  return {
    json: {
      ...json,
      source: cleanString(json.source, 'line_image'),
      job_id: cleanString(json.job_id, `line-image-${messageId}`),
      product_id: cleanString(json.product_id, `line-image-${messageId}`),
      messageId,
      owner_line_user_id: cleanString(json.userId || json.owner_line_user_id || json.ownerLineUserId),
      public_image_url: publicImageUrl,
      image_url: publicImageUrl,
      image_urls: [publicImageUrl],
      brand_context: brandContext,
      ...profile,
      price: '',
      real_posting_enabled: false,
      posting_allowed: false,
    },
  };
});

const staticData = $getWorkflowStaticData('global');

if (!staticData.brand_context_by_user) {
  staticData.brand_context_by_user = {};
}

const json = $input.all()[0]?.json || $json || {};
const event = json.body?.events?.[0] || json.events?.[0] || {};

const userId =
  json.userId ||
  json.user_id ||
  json.owner_line_user_id ||
  event.source?.userId ||
  '';

const text = String(
  json.text ||
  json.message?.text ||
  event.message?.text ||
  ''
).trim().toLowerCase();

const replyToken = event.replyToken || json.replyToken || '';

let brandContext = null;

if (
  text === 'syncflow' ||
  text === 'sf' ||
  text === '#syncflow' ||
  text.includes('syncflow') ||
  text.includes('ซิงค์โฟลว์')
) {
  brandContext = 'syncflow';
}

if (
  text === 'paa' ||
  text === 'paa_air' ||
  text === '#paa' ||
  text.includes('paa air') ||
  text.includes('pa cooling') ||
  text.includes('แอร์')
) {
  brandContext = 'paa_air';
}

if (!userId) {
  return [{
    json: {
      success: false,
      reason: 'missing_user_id',
      replyToken,
      real_posting_enabled: false,
      posting_allowed: false,
    }
  }];
}

if (!brandContext) {
  return [{
    json: {
      success: false,
      reason: 'not_brand_command',
      text,
      replyToken,
      real_posting_enabled: false,
      posting_allowed: false,
    }
  }];
}

const ttlMs = 10 * 60 * 1000;
const now = Date.now();

staticData.brand_context_by_user[userId] = {
  brand_context: brandContext,
  user_id: userId,
  saved_at: new Date(now).toISOString(),
  expires_at: new Date(now + ttlMs).toISOString(),
};

return [{
  json: {
    success: true,
    reason: 'brand_context_saved',
    brand_context: brandContext,
    brand_context_source: 'text_command',
    userId,
    user_id: userId,
    owner_line_user_id: userId,
    replyToken,
    reply_text:
      brandContext === 'syncflow'
        ? 'ตั้งค่าแบรนด์เป็น SyncFlow แล้ว ส่งรูปต่อได้เลย'
        : 'ตั้งค่าแบรนด์เป็น PAA Air แล้ว ส่งรูปต่อได้เลย',
    real_posting_enabled: false,
    posting_allowed: false,
  }
}];

const staticData = $getWorkflowStaticData('global');
const items = $input.all();
const now = Date.now();

if (!staticData.brand_context_by_user) {
  staticData.brand_context_by_user = {};
}

// Cleanup expired records.
for (const [key, value] of Object.entries(staticData.brand_context_by_user)) {
  const expiresAt = new Date(value?.expires_at || 0).getTime();
  if (!Number.isFinite(expiresAt) || expiresAt <= now) {
    delete staticData.brand_context_by_user[key];
  }
}

function cleanString(value, fallback = '') {
  if (value === null || value === undefined) return fallback;
  return String(value).trim();
}

function firstLineEvent(json) {
  if (Array.isArray(json?.events) && json.events.length > 0) {
    return json.events[0];
  }
  return null;
}

function getUserId(json) {
  const event = firstLineEvent(json);
  return cleanString(
    json.userId ||
    json.user_id ||
    json.owner_line_user_id ||
    json.ownerLineUserId ||
    json.source?.userId ||
    event?.source?.userId ||
    event?.source?.groupId ||
    ''
  );
}

function normalizeBrandContext(value) {
  const raw = cleanString(value).toLowerCase();
  if (!raw) return null;

  if (
    raw === 'syncflow' ||
    raw === 'sf' ||
    raw.includes('syncflow') ||
    raw.includes('paa tech') ||
    raw.includes('ซิงค์โฟลว์') ||
    raw.includes('ระบบจัดการแชท') ||
    raw.includes('รับแชท') ||
    raw.includes('คิวหลุด') ||
    raw.includes('งานไม่หลุด')
  ) {
    return 'syncflow';
  }

  if (
    raw === 'paa_air' ||
    raw === 'paa' ||
    raw === 'paair' ||
    raw.includes('paa air') ||
    raw.includes('pa air') ||
    raw.includes('pa cooling') ||
    raw.includes('paa cooling') ||
    raw.includes('ล้างแอร์') ||
    raw.includes('ซ่อมแอร์') ||
    raw.includes('ติดตั้งแอร์')
  ) {
    return 'paa_air';
  }

  return null;
}

return items.map((item) => {
  const json = item.json || {};
  const userId = getUserId(json);

  const explicitBrandSignal = [
    json.brand_context,
    json.brand,
    json.brand_name,
    json.business_name,
    json.product_name,
    json.caption,
    json.message,
    json.text,
    json.raw_text,
    json.notes,
  ]
    .filter((value) => value !== null && value !== undefined && String(value).trim() !== '')
    .join(' ');

  let brandContext = normalizeBrandContext(explicitBrandSignal);
  let brandContextSource = brandContext ? 'explicit_input' : null;

  if (!brandContext && userId && staticData.brand_context_by_user[userId]) {
    const saved = staticData.brand_context_by_user[userId];
    const expiresAt = new Date(saved.expires_at || 0).getTime();

    if (Number.isFinite(expiresAt) && expiresAt > now) {
      brandContext = normalizeBrandContext(saved.brand_context);
      brandContextSource = 'saved_user_state';
    } else {
      delete staticData.brand_context_by_user[userId];
    }
  }

  if (!brandContext) {
    brandContext = 'paa_air';
    brandContextSource = 'default_fallback';
  }

  return {
    json: {
      ...json,
      userId: userId || json.userId,
      user_id: userId || json.user_id,
      brand_context: brandContext,
      brand_context_source: brandContextSource,
      brand_context_note:
        brandContextSource === 'default_fallback'
          ? 'No explicit brand_context or active saved state found; fallback to paa_air.'
          : undefined,
      real_posting_enabled: false,
      posting_allowed: false,
    },
  };
});

const body = $json.body || $json;
const errors = [];

if (body.preview_only !== true) errors.push("preview_only_required");
if (body.real_posting_enabled !== false) errors.push("real_posting_must_be_false");
if (body.line_broadcast_enabled !== false) errors.push("line_broadcast_must_be_false");
if (body.schedule_enabled !== false) errors.push("schedule_must_be_false");

if (!body.brand_context) errors.push("brand_context_required");
if (!body.target_page_key) errors.push("target_page_key_required");
if (!body.selected_page_id) errors.push("selected_page_id_required");
if (!body.selected_page_name) errors.push("selected_page_name_required");

if (body.brand_context === "syncflow" && body.target_page_key !== "syncflow") {
  errors.push("syncflow_page_mismatch");
}

if (
  (body.brand_context === "paa" || body.brand_context === "paa_air") &&
  body.target_page_key !== "paa_air"
) {
  errors.push("paa_page_mismatch");
}

const accepted = errors.length === 0;
return [
  {
    json: {
      ok: accepted,
      status: accepted ? 200 : 400,
      endpoint: "product-video-preview",
      terminal_branch: true,
      preview_only: body.preview_only === true,
      accepted,
      errors,
      audit: {
        source: "ai-content-studio",
        brand_context: body.brand_context || null,
        target_page_key: body.target_page_key || null,
        selected_page_id: body.selected_page_id || null,
        selected_page_name: body.selected_page_name || null,
        platform: body.platform || "facebook_page",
        disabled_side_effects: [
          "real_posting",
          "line_broadcast",
          "schedule",
          "renderer",
          "phaya_openai_tts",
          "line_image_download",
          "s3_minio_upload",
          "facebook_graph",
          "mark_posted"
        ]
      },
      facebook_post_performed: false,
      line_broadcast_performed: false,
      schedule_triggered: false,
      renderer_called: false,
      phaya_called: false,
      s3_uploaded: false,
      mark_posted_performed: false,
      created_at: new Date().toISOString()
    }
  }
];

const body = $json.body || $json;

const previewId = String(body.preview_id || body.campaign_id || '').trim();
const brandRaw   = String(body.brand_context || 'paa_air').trim().toLowerCase();
const brandCtx   = brandRaw.includes('sync') ? 'syncflow' : 'paa_air';
const brief      = String(body.brief || '').trim();
const caption    = String(body.marketing_caption || body.publish_caption || '').trim();
const assetId    = String(body.asset_id || '').trim();
const sceneScript = String(body.scene_script || '').trim();
const overlayTexts = String(body.overlay_texts || '').trim();
const selectedPages = Array.isArray(body.selected_pages) ? body.selected_pages : [];
const pageId   = String(body.selected_page_id || '').trim();
const pageName = String(body.selected_page_name || '').trim();
const pageKey  = String(body.target_page_key || brandCtx).trim();

function clean(value) {
  return String(value ?? '').trim();
}

function isAbsoluteHttpUrl(value) {
  const s = clean(value);
  return s.startsWith('https://') || s.startsWith('http://');
}

function uniq(values) {
  const seen = new Set();
  const out = [];
  for (const value of values) {
    const s = clean(value);
    if (!s || seen.has(s)) continue;
    seen.add(s);
    out.push(s);
  }
  return out;
}

const rawImageCandidates = [
  ...(Array.isArray(body.image_urls)
    ? body.image_urls
    : (typeof body.image_urls === 'string' ? [body.image_urls] : [])),
  body.public_image_url,
  body.image_url,
  body.source_image_url,
  body.product_image_url,
  body.input_image_url,
  body.main_image_url,
  body.uploaded_image_url,
  body.primary_image_url,
  body.cover_image_url,
];

let imageUrls = uniq(rawImageCandidates).filter(isAbsoluteHttpUrl);
const studioAssetImageUrl = assetId
  ? `https://studio.paaair.online/api/product-video/assets/${encodeURIComponent(assetId)}`
  : '';
if (!imageUrls.length && studioAssetImageUrl) {
  imageUrls = [studioAssetImageUrl];
}
const imageUrl = imageUrls[0] || '';

if (!previewId) throw new Error('Missing preview_id or campaign_id');
if (!brandCtx) throw new Error('Missing brand_context');

return {
  json: {
    preview_id: previewId,
    brand_context: brandCtx,
    product_id: previewId,
    job_id: 'render-' + previewId,

    image_url: imageUrl,
    image_urls: imageUrls,
    public_image_url: imageUrl,
    source_image_url: imageUrl,
    product_image_url: imageUrl,

    brief: brief,
    marketing_caption: caption,
    scene_script: sceneScript,
    overlay_texts: overlayTexts,
    selected_pages: selectedPages,
    selected_page_id: pageId,
    selected_page_name: pageName,
    target_page_key: pageKey,

    product_name: brief || (brandCtx === 'syncflow' ? 'ระบบจัดการแชทและงานบริการ' : 'บริการตรวจเช็กและซ่อมแอร์'),
    target_customer: '',
    pain_point: '',
    benefits: '',
    offer: '',
    call_to_action: brandCtx === 'syncflow'
      ? 'ทัก LINE เพื่อดูเดโม SyncFlow'
      : 'ทัก LINE เพื่อสอบถามอาการแอร์',
    visual_context: brief,

    render_source: 'ai_studio_render',

    real_posting_enabled: false,
    posting_allowed: false,
    line_broadcast_enabled: false,
    schedule_enabled: false,
  }
};

const json = $json;

const publicMediaUrl = String(
  json.public_video_url || json.video_url || json.output_url || json.render_url || json.media_url || ''
).trim();

const thumbnailUrl = String(
  json.public_thumbnail_url || json.thumbnail_url || json.image_url || ''
).trim();

const ok = Boolean(publicMediaUrl);

return {
  json: {
    ok: ok,
    status: ok ? 'rendered' : 'render_failed',
    renderer_called: true,
    public_media_url: publicMediaUrl || null,
    thumbnail_url: thumbnailUrl || null,
    media_type: 'video',
    media_checksum: json.media_checksum || ('md5-' + (json.product_id || 'unknown')),
    render_job_id: json.job_id || json.product_id || null,
    preview_id: json.preview_id || json.product_id || null,
    facebook_post_performed: false,
    line_broadcast_performed: false,
    schedule_enabled: false,
    mark_posted_performed: false,
    error: ok ? null : 'render_failed',
  }
};
